   118→        where: { sessionId: s.sessionId },
   119→        create: {
   120→          sessionId: s.sessionId,
   121→          startedAt: new Date(s.startedAt),
   122→          updatedAt: new Date(s.updatedAt),
   123→          cwd: s.cwd,
   124→          repoRoot: s.repoRoot ?? null,
   125→          repoName: s.repoName ?? null,
   126→          parentSessionId: s.parentSessionId ?? null,
   127→          gitUserName: s.gitUserName ?? null,
   128→          gitUserEmail: s.gitUserEmail ?? null,
   129→          prompt: s.prompt ?? null,
   130→          summary: s.summary ?? null,
   131→          keywords: s.keywords ? JSON.stringify(s.keywords) : null,
   132→        },
   133→        update: {
   134→          updatedAt: new Date(s.updatedAt),
   135→          cwd: s.cwd,
   136→          repoRoot: s.repoRoot ?? null,
   137→          repoName: s.repoName ?? null,
   138→          parentSessionId: s.parentSessionId ?? null,
   139→          gitUserName: s.gitUserName ?? null,
   140→          gitUserEmail: s.gitUserEmail ?? null,
   141→          prompt: s.prompt ?? null,
   142→          summary: s.summary ?? null,
   143→          keywords: s.keywords ? JSON.stringify(s.keywords) : null,
   144→        },
   145→      })
   146→    )
   147→  );
   148→
   149→  // Replace agentParents wholesale
   150→  await db.agentParent.deleteMany();
   151→  const agentEntries = Object.entries(state.agentParents);
   152→  if (agentEntries.length > 0) {
   153→    await db.agentParent.createMany({
   154→      data: agentEntries.map(([agentId, parentSessionId]) => ({ agentId, parentSessionId })),
   155→    });
   156→  }
   157→
   158→  // Replace pendingToolUses wholesale
   159→  await db.pendingToolUse.deleteMany();
   160→  const pendingEntries = Object.values(state.pendingToolUses);
   161→  if (pendingEntries.length > 0) {
   162→    await db.pendingToolUse.createMany({
   163→      data: pendingEntries.map((p) => ({
   164→        toolUseId: p.tool_use_id,
   165→        toolName: p.tool_name,
   166→        toolInput: p.tool_input !== undefined ? JSON.stringify(p.tool_input) : null,
   167→        startedAt: p.startedAt,
   168→      })),
   169→    });
   170→  }
   171→}
