  1005→// ─── CLI ──────────────────────────────────────────────────────────────────────
  1006→
  1007→async function main(): Promise<void> {
  1008→  const config = loadConfig();
  1009→
  1010→  const defaultDbPath = config.repository
  1011→    ? join(expandHome(config.repository), "hook-handler.db")
  1012→    : expandHome("~/.claude/hook-handler.db");
  1013→  const defaultSessionsPath = config.repository
  1014→    ? join(expandHome(config.repository), "sessions.md")
  1015→    : expandHome("~/.claude/sessions.md");
  1016→
  1017→  const program = new Command();
  1018→
  1019→  program
  1020→    .name("claude-hook-handler")
  1021→    .description(
  1022→      "Stdin hook handler for Claude Code's settings-based hook system.\n" +
  1023→        "Maintains a live markdown sessions table and writes a JSON response to stdout.",
  1024→    )
  1025→    .version("1.0.0")
  1026→    .enablePositionalOptions();
  1027→
  1028→  // ── reconstruct subcommand ───────────────────────────────────────────────
  1029→  program
  1030→    .command("reconstruct")
  1031→    .description(
  1032→      "Rebuild markdown session files from the SQLite event log.\n" +
  1033→        "Clears existing markdown output and replays all recorded events.",
  1034→    )
  1035→    .option(
  1036→      "--db <file>",
  1037→      "SQLite database file",
  1038→      defaultDbPath,
  1039→    )
  1040→    .option(
  1041→      "-s, --sessions <file>",
  1042→      "Markdown sessions table to write",
  1043→      defaultSessionsPath,
  1044→    )
  1045→    .option(
  1046→      "--max-log-lines <n>",
  1047→      "Rotate session log files after this many lines (0 to disable)",
  1048→      (v: string) => parseInt(v, 10),
  1049→      1000,
  1050→    )
  1051→    .option("--no-summary", "Skip AI summarisation, use truncated prompt text instead")
  1052→    .action(async (opts: {
  1053→      db: string;
  1054→      sessions: string;
  1055→      maxLogLines: number;
  1056→      summary: boolean;
  1057→    }) => {
  1058→      const db = await getDb(expandHome(opts.db));
  1059→      await runReconstruct(db, opts.sessions, opts.maxLogLines, !opts.summary);
  1060→    });
  1061→
  1062→  // ── migrate subcommand ───────────────────────────────────────────────────
  1063→  program
  1064→    .command("migrate")
  1065→    .description(
  1066→      "Migrate events from an NDJSON event log into a SQLite database.\n" +
  1067→        "After inserting all events, runs reconstruct to rebuild session markdown.",
  1068→    )
  1069→    .requiredOption(
  1070→      "--events <file>",
  1071→      "Source NDJSON event log to read",
  1072→    )
  1073→    .option(
  1074→      "--db <file>",
  1075→      "Destination SQLite database file",
  1076→      defaultDbPath,
  1077→    )
  1078→    .option(
  1079→      "-s, --sessions <file>",
  1080→      "Markdown sessions table to write",
  1081→      defaultSessionsPath,
  1082→    )
  1083→    .option(
  1084→      "--max-log-lines <n>",
  1085→      "Rotate session log files after this many lines (0 to disable)",
  1086→      (v: string) => parseInt(v, 10),
  1087→      1000,
  1088→    )
  1089→    .option("--no-summary", "Skip AI summarisation, use truncated prompt text instead")
  1090→    .action(async (opts: {
  1091→      events: string;
  1092→      db: string;
  1093→      sessions: string;
  1094→      maxLogLines: number;
  1095→      summary: boolean;
  1096→    }) => {
  1097→      const db = await getDb(expandHome(opts.db));
  1098→      await runMigrate(opts.events, db, opts.sessions, opts.maxLogLines, !opts.summary);
  1099→    });
  1100→
  1101→  // ── default: stdin hook handler ──────────────────────────────────────────
  1102→  program
  1103→    .option(
  1104→      "--db <file>",
  1105→      "SQLite database file for event log and session state",
  1106→      defaultDbPath,
  1107→    )
  1108→    .option(
  1109→      "-s, --sessions <file>",
  1110→      "Markdown sessions table to maintain",
  1111→      defaultSessionsPath,
  1112→    )
  1113→    .option(
  1114→      "-b, --block <pattern>",
  1115→      "Regex of tool names to block (repeatable, PreToolUse only)",
  1116→      (v: string, acc: string[]) => [...acc, v],
  1117→      [] as string[],
  1118→    )
  1119→    .option(
  1120→      "--block-reason <reason>",
  1121→      "Message sent to Claude when a tool is blocked",
  1122→      "Blocked by claude-hook-handler",
  1123→    )
  1124→    .option(
  1125→      "--no-summary",
  1126→      "Skip AI summarisation, use truncated prompt text instead",
  1127→    )
  1128→    .option(
  1129→      "--max-log-lines <n>",
  1130→      "Rotate session log files after this many lines (0 to disable)",
  1131→      (v: string) => parseInt(v, 10),
  1132→      1000,
  1133→    )
  1134→    .option("--quiet", "Suppress stderr output")
  1135→    .action(async () => {
  1136→      const opts = program.opts<{
  1137→        db: string;
  1138→        sessions: string;
  1139→        block: string[];
  1140→        blockReason: string;
  1141→        summary: boolean; // commander sets this from --no-summary
  1142→        maxLogLines: number;
  1143→        quiet?: boolean;
  1144→      }>();
  1145→
  1146→      const sessionsPath = expandHome(opts.sessions);
  1147→      const blockPatterns = opts.block.map((p) => new RegExp(p));
  1148→      const noSummary = !opts.summary;
  1149→
  1150→      // Read stdin
  1151→      let raw: string;
  1152→      try {
  1153→        raw = await readStdin();
  1154→      } catch (err) {
  1155→        process.stderr.write(`claude-hook-handler: failed to read stdin: ${err}\n`);
  1156→        process.exit(1);
  1157→      }
  1158→
  1159→      let input: HookInput;
  1160→      try {
  1161→        input = JSON.parse(raw) as HookInput;
  1162→      } catch {
  1163→        process.stderr.write(
  1164→          `claude-hook-handler: invalid JSON on stdin:\n${raw.slice(0, 200)}\n`,
  1165→        );
  1166→        process.exit(1);
  1167→      }
  1168→
  1169→      const blocked = shouldBlock(input, blockPatterns);
  1170→
  1171→      if (input.hook_event_name !== "Setup") {
  1172→        try {
  1173→          const db = await getDb(expandHome(opts.db));
  1174→          const state = await readStateFromDb(db);
  1175→
  1176→          // 1. Compute derived state (summary/keywords via AI if needed)
  1177→          await applyEvent(state, input, noSummary);
  1178→
  1179→          // 2. Write to SQLite event log — primary source of truth
  1180→          await writeEventLog(db, input, blocked, state);
  1181→
  1182→          // 3. Derive markdown from state
  1183→          writeMarkdown(sessionsPath, state);
  1184→          const logPaths = appendSessionLog(sessionsPath, input, state, opts.maxLogLines);
  1185→
  1186→          // 4. Persist state (after appendSessionLog so pendingToolUses mutations are saved)
  1187→          await writeStateToDb(db, state);
  1188→
  1189→          commitFiles(sessionsPath, [sessionsPath, ...logPaths], buildCommitMessage(input, state));
  1190→        } catch (err) {
  1191→          process.stderr.write(
  1192→            `claude-hook-handler: failed to update sessions table: ${err}\n`,
  1193→          );
  1194→          // Non-fatal — Claude Code must still get a response
  1195→        }
  1196→      }
  1197→
  1198→      // stderr summary (visible inside Claude Code)
  1199→      if (!opts.quiet) {
  1200→        process.stderr.write(formatForStderr(input, blocked) + "\n");
  1201→      }
  1202→
  1203→      // JSON response to stdout
  1204→      process.stdout.write(
  1205→        JSON.stringify(buildResponse(blocked, opts.blockReason)) + "\n",
  1206→      );
  1207→    });
  1208→
  1209→  await program.parseAsync();
  1210→}
  1211→
  1212→main().catch((err: Error) => {
  1213→  process.stderr.write(`claude-hook-handler: fatal: ${err.message}\n`);
  1214→  process.exit(1);
  1215→});
