Now I have a thorough understanding of the codebase. Let me design the complete implementation plan.

---

## Implementation Plan: HTTP + WebSocket Server and Expo Web App

### Overview

The plan adds two things to the gossamer project:
1. `src/server.ts` — Express HTTP + `ws` WebSocket server, registered as a `serve` subcommand on the existing `commander` `program` in `handler.ts`
2. `app/` — Expo project targeting web, consuming the HTTP and WebSocket APIs

---

## Part 1: Root Package Changes

### `package.json` — Changes Required

Add to `"scripts"`:
```json
"serve": "node dist/handler.js serve"
```

Add to `"dependencies"`:
```json
"cors": "^2.8.5",
"express": "^4.18.2",
"ws": "^8.18.0"
```

Add to `"devDependencies"`:
```json
"@types/cors": "^2.8.17",
"@types/express": "^4.17.21",
"@types/ws": "^8.5.12"
```

No `tsconfig.json` changes are needed. The `"include": ["src/**/*"]` glob already picks up `src/server.ts`.

---

## Part 2: `src/server.ts`

This is the largest new file on the server side. It must be a proper ES module (`.ts` with NodeNext module resolution), which means all internal imports must use `.js` extensions.

### Imports

```typescript
import express, { type Request, type Response } from "express";
import cors from "cors";
import { WebSocketServer, WebSocket } from "ws";
import { createServer } from "http";
import { getDb } from "./db.js";
import type { PrismaClient } from "../prisma/generated/client/index.js";
import { expandHome } from "./utils.js";  // OR inline the helper
```

**NodeNext import extension note:** Every import from a local `.ts` file must use the `.js` extension at the call site (compiled output path). The existing code in `handler.ts` already does this consistently (`"./db.js"`, `"../prisma/generated/client/index.js"`).

### JSON Response Shapes

**`GET /api/sessions`**

```typescript
// Array of:
interface SessionResponse {
  sessionId: string;
  startedAt: string;       // ISO 8601
  updatedAt: string;       // ISO 8601
  cwd: string;
  repoRoot: string | null;
  repoName: string | null;
  parentSessionId: string | null;
  gitUserName: string | null;
  gitUserEmail: string | null;
  prompt: string | null;
  summary: string | null;
  keywords: string[];      // parsed from JSON text, never null
}
```

**`GET /api/sessions/:id`**

Same shape as above, single object. Returns 404 with `{ error: "Not found" }` if missing.

**`GET /api/sessions/:id/events`**

```typescript
// Array of:
interface EventResponse {
  id: number;
  timestamp: string;       // ISO 8601
  event: string;           // hook_event_name
  sessionId: string;
  blocked: boolean;
  data: unknown;           // parsed JSON (full HookInput object)
  summary: string | null;
  keywords: string[];      // parsed from JSON text
}
```

### Route Handlers

```typescript
function mapSession(s: PrismaSession): SessionResponse {
  return {
    ...s,
    startedAt: s.startedAt instanceof Date ? s.startedAt.toISOString() : String(s.startedAt),
    updatedAt: s.updatedAt instanceof Date ? s.updatedAt.toISOString() : String(s.updatedAt),
    keywords: s.keywords ? (JSON.parse(s.keywords) as string[]) : [],
    repoRoot: s.repoRoot ?? null,
    repoName: s.repoName ?? null,
    parentSessionId: s.parentSessionId ?? null,
    gitUserName: s.gitUserName ?? null,
    gitUserEmail: s.gitUserEmail ?? null,
    prompt: s.prompt ?? null,
    summary: s.summary ?? null,
  };
}

function mapEvent(e: PrismaEvent): EventResponse {
  return {
    id: e.id,
    timestamp: e.timestamp instanceof Date ? e.timestamp.toISOString() : String(e.timestamp),
    event: e.event,
    sessionId: e.sessionId,
    blocked: e.blocked,
    data: JSON.parse(e.data) as unknown,
    summary: e.summary ?? null,
    keywords: e.keywords ? (JSON.parse(e.keywords) as string[]) : [],
  };
}
```

### WebSocket Change Detection

The simplest reliable strategy: poll the `Event` table every 2 seconds for the max `id`. When it changes, broadcast `{ type: "sessions_updated" }` to all connected clients.

```typescript
function startChangePoller(db: PrismaClient, wss: WebSocketServer): NodeJS.Timeout {
  let lastMaxId = -1;

  return setInterval(async () => {
    try {
      const latest = await db.event.findFirst({ orderBy: { id: "desc" } });
      const currentMaxId = latest?.id ?? -1;
      if (currentMaxId !== lastMaxId) {
        lastMaxId = currentMaxId;
        const msg = JSON.stringify({ type: "sessions_updated" });
        for (const client of wss.clients) {
          if (client.readyState === WebSocket.OPEN) {
            client.send(msg);
          }
        }
      }
    } catch {
      // non-fatal — server keeps running
    }
  }, 2000);
}
```

### Main `createServer` function

```typescript
export async function startServer(dbPath: string, port: number): Promise<void> {
  const db = await getDb(dbPath);
  const app = express();

  app.use(cors());
  app.use(express.json());

  // Routes
  app.get("/api/sessions", async (_req: Request, res: Response) => {
    const sessions = await db.session.findMany({ orderBy: { updatedAt: "desc" } });
    res.json(sessions.map(mapSession));
  });

  app.get("/api/sessions/:id", async (req: Request, res: Response) => {
    const session = await db.session.findUnique({ where: { sessionId: req.params.id } });
    if (!session) { res.status(404).json({ error: "Not found" }); return; }
    res.json(mapSession(session));
  });

  app.get("/api/sessions/:id/events", async (req: Request, res: Response) => {
    const events = await db.event.findMany({
      where: { sessionId: req.params.id },
      orderBy: { timestamp: "asc" },
    });
    res.json(events.map(mapEvent));
  });

  const httpServer = createServer(app);
  const wss = new WebSocketServer({ server: httpServer });

  wss.on("connection", (ws) => {
    ws.on("error", () => { /* ignore */ });
  });

  const poller = startChangePoller(db, wss);

  httpServer.listen(port, () => {
    process.stderr.write(`claude-hook-handler serve: listening on http://localhost:${port}\n`);
    process.stderr.write(`  WebSocket: ws://localhost:${port}\n`);
  });

  // Clean shutdown on SIGINT/SIGTERM
  const shutdown = () => {
    clearInterval(poller);
    httpServer.close();
    process.exit(0);
  };
  process.on("SIGINT", shutdown);
  process.on("SIGTERM", shutdown);
}
```

### Integration into `handler.ts`

Add the following subcommand block inside `main()`, after the `migrate` subcommand and before the default stdin handler:

```typescript
// ── serve subcommand ─────────────────────────────────────────────────────
program
  .command("serve")
  .description("Start the HTTP + WebSocket API server.")
  .option("--db <file>", "SQLite database file", defaultDbPath)
  .option("--port <n>", "Port to listen on", (v: string) => parseInt(v, 10), 3000)
  .action(async (opts: { db: string; port: number }) => {
    const { startServer } = await import("./server.js");
    await startServer(expandHome(opts.db), opts.port);
  });
```

Using a dynamic `import()` keeps `server.ts` lazily loaded (express/ws are heavy) and avoids any startup cost for the default stdin-handler path. This is valid in NodeNext ESM.

**CORS consideration:** The app will run on `localhost:19006` (Expo web) and the API on `localhost:3000`. The `cors()` middleware with no options allows all origins by default, which is appropriate for a local dev tool. No production CORS configuration is needed.

---

## Part 3: `app/` — Expo Web Project

### `app/package.json`

```json
{
  "name": "gossamer-app",
  "version": "1.0.0",
  "private": true,
  "main": "node_modules/expo/AppEntry.js",
  "scripts": {
    "start": "expo start",
    "web": "expo start --web",
    "build:web": "expo export -p web"
  },
  "dependencies": {
    "@react-navigation/native": "^6.1.18",
    "@react-navigation/stack": "^6.3.29",
    "expo": "~52.0.0",
    "react": "18.3.2",
    "react-dom": "18.3.2",
    "react-native": "0.76.3",
    "react-native-safe-area-context": "4.12.0",
    "react-native-screens": "~4.4.0",
    "react-native-web": "~0.19.13"
  },
  "devDependencies": {
    "@babel/core": "^7.24.0",
    "@types/react": "~18.3.0",
    "@types/react-native": "~0.76.0",
    "typescript": "~5.3.3"
  }
}
```

**Why these versions:** Expo 52 ships with React Native 0.76.x and React 18.3.x. The `@react-navigation/stack` v6 is compatible with Expo 52. `react-native-web` 0.19.x is the version expo ships with for web target.

### `app/babel.config.js`

```javascript
module.exports = function (api) {
  api.cache(true);
  return {
    presets: ['babel-preset-expo'],
  };
};
```

### `app/tsconfig.json`

```json
{
  "extends": "expo/tsconfig.base",
  "compilerOptions": {
    "strict": true,
    "paths": {
      "@/*": ["./src/*"]
    }
  },
  "include": ["**/*.ts", "**/*.tsx", ".expo/types/**/*.d.ts", "expo-env.d.ts"]
}
```

This is separate from the root `tsconfig.json` (which uses NodeNext for the server). Expo uses its own base that targets bundler module resolution rather than NodeNext, so the two configs must not be merged.

### `app/App.tsx`

```typescript
import { NavigationContainer } from '@react-navigation/native';
import { createStackNavigator } from '@react-navigation/stack';
import { SafeAreaProvider } from 'react-native-safe-area-context';
import ActiveSessions from './src/screens/ActiveSessions';
import SessionDetail from './src/screens/SessionDetail';

export type RootStackParamList = {
  ActiveSessions: undefined;
  SessionDetail: { sessionId: string; title?: string };
};

const Stack = createStackNavigator<RootStackParamList>();

export default function App() {
  return (
    <SafeAreaProvider>
      <NavigationContainer>
        <Stack.Navigator initialRouteName="ActiveSessions">
          <Stack.Screen
            name="ActiveSessions"
            component={ActiveSessions}
            options={{ title: 'Claude Sessions' }}
          />
          <Stack.Screen
            name="SessionDetail"
            component={SessionDetail}
            options={({ route }) => ({ title: route.params.title ?? route.params.sessionId.slice(0, 8) + '…' })}
          />
        </Stack.Navigator>
      </NavigationContainer>
    </SafeAreaProvider>
  );
}
```

### `app/src/api.ts`

This file handles all network communication. Key design decisions:

1. `API_BASE` is a plain constant — easy to change for production
2. The WebSocket auto-reconnect uses exponential backoff capped at 30 seconds
3. `subscribeToUpdates` returns an unsubscribe function, following the React `useEffect` cleanup pattern

```typescript
export const API_BASE = 'http://localhost:3000/api';
export const WS_URL = 'ws://localhost:3000';

export interface Session {
  sessionId: string;
  startedAt: string;
  updatedAt: string;
  cwd: string;
  repoRoot: string | null;
  repoName: string | null;
  parentSessionId: string | null;
  gitUserName: string | null;
  gitUserEmail: string | null;
  prompt: string | null;
  summary: string | null;
  keywords: string[];
}

export interface Event {
  id: number;
  timestamp: string;
  event: string;
  sessionId: string;
  blocked: boolean;
  data: Record<string, unknown>;
  summary: string | null;
  keywords: string[];
}

export async function fetchSessions(): Promise<Session[]> {
  const res = await fetch(`${API_BASE}/sessions`);
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json() as Promise<Session[]>;
}

export async function fetchSessionEvents(id: string): Promise<Event[]> {
  const res = await fetch(`${API_BASE}/sessions/${encodeURIComponent(id)}/events`);
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json() as Promise<Event[]>;
}

export function subscribeToUpdates(onUpdate: () => void): () => void {
  let ws: WebSocket | null = null;
  let timer: ReturnType<typeof setTimeout> | null = null;
  let destroyed = false;
  let delay = 1000;

  function connect() {
    if (destroyed) return;
    ws = new WebSocket(WS_URL);

    ws.onopen = () => { delay = 1000; };

    ws.onmessage = (e) => {
      try {
        const msg = JSON.parse(e.data as string) as { type: string };
        if (msg.type === 'sessions_updated') onUpdate();
      } catch { /* ignore */ }
    };

    ws.onclose = () => {
      if (destroyed) return;
      timer = setTimeout(() => {
        delay = Math.min(delay * 2, 30_000);
        connect();
      }, delay);
    };

    ws.onerror = () => { ws?.close(); };
  }

  connect();

  return () => {
    destroyed = true;
    if (timer) clearTimeout(timer);
    ws?.close();
  };
}
```

**Note:** `WebSocket` is available globally in web browsers and in React Native, so no import is needed. On React Native (non-web), RN ships a built-in WebSocket polyfill.

### `app/src/screens/ActiveSessions.tsx`

```typescript
import { useCallback, useEffect, useState } from 'react';
import { FlatList, RefreshControl, StyleSheet, Text, TouchableOpacity, View } from 'react-native';
import type { NativeStackScreenProps } from '@react-navigation/native-stack';
import { fetchSessions, subscribeToUpdates, type Session } from '../api';
import SessionRow from '../components/SessionRow';
import type { RootStackParamList } from '../../App';

type Props = NativeStackScreenProps<RootStackParamList, 'ActiveSessions'>;

export default function ActiveSessions({ navigation }: Props) {
  const [sessions, setSessions] = useState<Session[]>([]);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const load = useCallback(async () => {
    try {
      const data = await fetchSessions();
      // Sort by updatedAt descending
      data.sort((a, b) => b.updatedAt.localeCompare(a.updatedAt));
      setSessions(data);
      setError(null);
    } catch (e) {
      setError(String(e));
    }
  }, []);

  // Initial load + WebSocket subscription
  useEffect(() => {
    void load();
    const unsub = subscribeToUpdates(() => { void load(); });
    return unsub;
  }, [load]);

  const onRefresh = useCallback(async () => {
    setRefreshing(true);
    await load();
    setRefreshing(false);
  }, [load]);

  if (error) {
    return (
      <View style={styles.center}>
        <Text style={styles.errorText}>Failed to load sessions: {error}</Text>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      {/* Table header row */}
      <View style={[styles.row, styles.headerRow]}>
        {['Session', 'User', 'Repo', 'Summary', 'Keywords', 'Started', 'Updated'].map((h) => (
          <Text key={h} style={[styles.cell, styles.headerCell]}>{h}</Text>
        ))}
      </View>

      <FlatList
        data={sessions}
        keyExtractor={(s) => s.sessionId}
        renderItem={({ item }) => (
          <SessionRow
            session={item}
            onPress={() =>
              navigation.push('SessionDetail', {
                sessionId: item.sessionId,
                title: item.summary ?? undefined,
              })
            }
          />
        )}
        refreshControl={<RefreshControl refreshing={refreshing} onRefresh={onRefresh} />}
      />
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: '#fff' },
  center: { flex: 1, justifyContent: 'center', alignItems: 'center' },
  errorText: { color: 'red', padding: 16 },
  row: { flexDirection: 'row', borderBottomWidth: 1, borderColor: '#eee', paddingVertical: 6, paddingHorizontal: 8 },
  headerRow: { backgroundColor: '#f5f5f5' },
  cell: { flex: 1, fontSize: 12, paddingHorizontal: 4 },
  headerCell: { fontWeight: 'bold' },
});
```

### `app/src/screens/SessionDetail.tsx`

```typescript
import { useEffect, useState } from 'react';
import { ActivityIndicator, ScrollView, StyleSheet, Text, View } from 'react-native';
import type { NativeStackScreenProps } from '@react-navigation/native-stack';
import { fetchSessionEvents, type Event } from '../api';
import EventItem from '../components/EventItem';
import type { RootStackParamList } from '../../App';

type Props = NativeStackScreenProps<RootStackParamList, 'SessionDetail'>;

export default function SessionDetail({ route }: Props) {
  const { sessionId } = route.params;
  const [events, setEvents] = useState<Event[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    fetchSessionEvents(sessionId)
      .then((data) => { setEvents(data); })
      .catch((e: unknown) => { setError(String(e)); })
      .finally(() => { setLoading(false); });
  }, [sessionId]);

  if (loading) return <ActivityIndicator style={styles.center} size="large" />;
  if (error) return <View style={styles.center}><Text style={styles.errorText}>{error}</Text></View>;

  return (
    <ScrollView style={styles.container}>
      {events.map((ev) => <EventItem key={ev.id} event={ev} />)}
      {events.length === 0 && <Text style={styles.empty}>No events recorded for this session.</Text>}
    </ScrollView>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: '#fff' },
  center: { flex: 1, justifyContent: 'center', alignItems: 'center' },
  errorText: { color: 'red', padding: 16 },
  empty: { padding: 24, color: '#888', textAlign: 'center' },
});
```

### `app/src/components/SessionRow.tsx`

