function mapSession(s: PrismaSession): SessionResponse {
  return {
    ...s,
    startedAt: s.startedAt instanceof Date ? s.startedAt.toISOString() : String(s.startedAt),
    updatedAt: s.updatedAt instanceof Date ? s.updatedAt.toISOString() : String(s.updatedAt),
    keywords: s.keywords ? (JSON.parse(s.keywords) as string[]) : [],
    repoRoot: s.repoRoot ?? null,
    repoName: s.repoName ?? null,
    parentSessionId: s.parentSessionId ?? null,
    gitUserName: s.gitUserName ?? null,
    gitUserEmail: s.gitUserEmail ?? null,
    prompt: s.prompt ?? null,
    summary: s.summary ?? null,
  };
}

function mapEvent(e: PrismaEvent): EventResponse {
  return {
    id: e.id,
    timestamp: e.timestamp instanceof Date ? e.timestamp.toISOString() : String(e.timestamp),
    event: e.event,
    sessionId: e.sessionId,
    blocked: e.blocked,
    data: JSON.parse(e.data) as unknown,
    summary: e.summary ?? null,
    keywords: e.keywords ? (JSON.parse(e.keywords) as string[]) : [],
  };
}
