import { useState } from 'react';
import { StyleSheet, Text, TouchableOpacity, View } from 'react-native';
import type { Event } from '../api';

const EVENT_SYMBOL: Record<string, string> = {
  PreToolUse: '▶', PostToolUse: '✓', PostToolUseFailure: '✗',
  SessionStart: '◉', SessionEnd: '◎', Stop: '■',
  UserPromptSubmit: '→', Notification: '◆', Setup: '⚙',
  SubagentStart: '▷', SubagentStop: '◁', PermissionRequest: '?', PreCompact: '⌃',
};

const EVENT_COLOR: Record<string, string> = {
  PostToolUse: '#16a34a', PostToolUseFailure: '#dc2626', UserPromptSubmit: '#7c3aed',
  Stop: '#2563eb', Notification: '#d97706', SessionEnd: '#dc2626',
};

interface Props { event: Event; }

export default function EventItem({ event }: Props) {
  const [expanded, setExpanded] = useState(false);
  const sym = EVENT_SYMBOL[event.event] ?? '◆';
  const color = EVENT_COLOR[event.event] ?? '#555';
  const data = event.data as Record<string, unknown>;

  const toolName = typeof data.tool_name === 'string' ? data.tool_name : null;
  const prompt = typeof data.prompt === 'string' ? data.prompt : null;
  const message = typeof (data.last_assistant_message ?? data.message) === 'string'
    ? String(data.last_assistant_message ?? data.message)
    : null;

  const ts = new Date(event.timestamp).toLocaleTimeString();
  const isExpandable = event.event.includes('ToolUse') || event.event === 'SubagentStart';

  return (
    <TouchableOpacity onPress={() => isExpandable && setExpanded((v) => !v)} activeOpacity={isExpandable ? 0.7 : 1}>
      <View style={styles.container}>
        <Text style={[styles.sym, { color }]}>{sym}</Text>
        <View style={styles.body}>
          <View style={styles.headerRow}>
            <Text style={[styles.eventName, { color }]}>{event.event}</Text>
            {toolName && <Text style={styles.toolName}>{toolName}</Text>}
            <Text style={styles.ts}>{ts}</Text>
          </View>

          {prompt && (
            <Text style={styles.quoteText} numberOfLines={expanded ? undefined : 3}>
              {prompt}
            </Text>
          )}
          {message && !prompt && (
            <Text style={styles.quoteText} numberOfLines={expanded ? undefined : 3}>
              {message}
            </Text>
          )}

          {isExpandable && expanded && (
            <View style={styles.jsonBlock}>
              <Text style={styles.jsonText}>
                {JSON.stringify(data.tool_input ?? data, null, 2).slice(0, 800)}
              </Text>
            </View>
          )}

          {event.blocked && <Text style={styles.blockedTag}>BLOCKED</Text>}
        </View>
      </View>
    </TouchableOpacity>
  );
}

const styles = StyleSheet.create({
  container: { flexDirection: 'row', padding: 10, borderBottomWidth: 1, borderColor: '#f0f0f0' },
  sym: { fontSize: 16, marginRight: 10, marginTop: 1 },
  body: { flex: 1 },
  headerRow: { flexDirection: 'row', alignItems: 'center', gap: 8 },
  eventName: { fontWeight: '600', fontSize: 13 },
  toolName: { fontSize: 12, color: '#888', fontFamily: 'monospace' },
  ts: { fontSize: 11, color: '#aaa', marginLeft: 'auto' },
  quoteText: { marginTop: 4, fontSize: 12, color: '#555', fontStyle: 'italic' },
  jsonBlock: { marginTop: 6, backgroundColor: '#f5f5f5', borderRadius: 4, padding: 8 },
  jsonText: { fontFamily: 'monospace', fontSize: 10, color: '#333' },
  blockedTag: { marginTop: 4, fontSize: 10, color: '#dc2626', fontWeight: 'bold' },
});
